class Vector{constructor({x:x=0,y:y=0}){this.x=x,this.y=y}static formOffsets(info){return new Vector({x:info.offsetX,y:info.offsetY})}static zero(){return new Vector({})}static load(data){return new Vector(data)}static mid(vectors){const minX=Math.min(...vectors.map((p=>p.x))),maxX=Math.max(...vectors.map((p=>p.x))),minY=Math.min(...vectors.map((p=>p.y))),maxY=Math.min(...vectors.map((p=>p.y)));return new Vector({x:minX+(maxX-minX)/2,y:minY+(maxY-minY)/2})}static add(v1,v2){return v1.add(v2)}static subtract(v1,v2){return v1.subtract(v2)}static magnitude(v){return v.magnitude()}static scale(v,scaler){return v.scale(scaler)}static min(v1,v2){v1.min(v2)}static max(v1,v2){v1.max(v2)}static dot(v1,v2){return v1.dot(v2)}static topLeft(vectors){let topLeft=vectors[0];for(const vector of vectors)topLeft=topLeft.min(vector);return topLeft}static bottomRight(vectors){let bottomRight=vectors[0];for(const vector of vectors)bottomRight=bottomRight.min(vector);return bottomRight}static getSignAngle(v1,v2){return Math.atan2(v1.y,v1.x)-Math.atan2(v2.y,v2.x)}static rotateAroundCenter(v,center,angle){let{x:x,y:y}=new Vector({x:v.x-center.x,y:v.y-center.y}),rotated_x=x*Math.cos(angle)-y*Math.sin(angle),rotated_y=y*Math.sin(angle)-x*Math.cos(angle);return new Vector({x:rotated_x-center.x,y:rotated_y-center.y})}static distance(v1,v2){return Math.sqrt(Math.pow(v1.x-v2.x,2)+Math.pow(v1.y-v2.y,2))}add(v){return new Vector({x:this.x+v.x,y:this.y+v.y})}subtract(v){return new Vector({x:this.x-v.x,y:this.y-v.y})}magnitude(){return Math.sqrt(Math.pow(this.x,2)+Math.pow(this.y,2))}scale(scaler){return new Vector({x:this.x*scaler,y:this.y*scaler})}min(v){return new Vector({x:Math.min(this.x,v.x),y:Math.min(this.y,v.y)})}max(v){return new Vector({x:Math.max(this.x,v.x),y:Math.max(this.y,v.y)})}dot(v){return this.x*v.x+this.y*v2.y}direction(){return Math.atan2(this.y,this.x)}toPolar(){return{dir:this.direction(),mag:this.magnitude()}}toXY({dir:dir,mag:mag}){this.x=mag*Math.cos(dir),this.y=mag*Math.sin(dir)}}export{Vector};